233→    const hitDistance = radiusPx + strokeWidth * 0.5;
234→
235→    const points = doodle.points;
236→    for(let i = 0; i < points.length - 2; i += 2){
237→        const dist = distancePointToSegment(
238→            pointerX,
239→            pointerY,
240→            points[i],
241→            points[i + 1],
242→            points[i + 2],
243→            points[i + 3]
244→        );
245→        if(dist <= hitDistance){
246→            return true;
247→        }
248→    }
249→
250→    return false;
251→};
