399→const darkenColor = (hex, amount = 0.15) => {
400→    const raw = hex?.replace("#", "") || "fff4a8";

400→    const raw = hex?.replace("#", "") || "fff4a8";
401→    const num = parseInt(raw.length === 3 ? raw.split("").map((c) => c + c).join("") : raw, 16);
402→    const r = Math.max(0, Math.round(((num >> 16) & 255) * (1 - amount)));
403→    const g = Math.max(0, Math.round(((num >> 8) & 255) * (1 - amount)));
